import{_ as t,o,c as r,a2 as a}from"./chunks/framework.CKCxdkvf.js";const u=JSON.parse(`{"title":"00 · Orrery — Introduction & Reader's Guide","description":"","frontmatter":{},"headers":[],"relativePath":"concept/00_Introduction.md","filePath":"concept/00_Introduction.md"}`),i={name:"concept/00_Introduction.md"};function n(s,e,d,h,c,l){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_00-·-orrery-—-introduction-reader-s-guide" tabindex="-1">00 · Orrery — Introduction &amp; Reader&#39;s Guide <a class="header-anchor" href="#_00-·-orrery-—-introduction-reader-s-guide" aria-label="Permalink to &quot;00 · Orrery — Introduction &amp; Reader&#39;s Guide&quot;">​</a></h1><p><em>April 2026 · v1.0 · Part of the Orrery Concept Package (00 through 05)</em></p><hr><h2 id="what-this-package-is" tabindex="-1">What this package is <a class="header-anchor" href="#what-this-package-is" aria-label="Permalink to &quot;What this package is&quot;">​</a></h2><p>This is the Orrery Concept Package — five documents and six working prototypes that together fully specify an open-source solar system explorer and Mars mission simulator.</p><p>It was built in the right order: prototypes first, documents second. Every design decision, every data choice, every architectural constraint in these documents is grounded in what the six prototype screens actually do. Nothing here is aspirational. The prototypes are the ground truth.</p><hr><h2 id="how-to-read-it" tabindex="-1">How to read it <a class="header-anchor" href="#how-to-read-it" aria-label="Permalink to &quot;How to read it&quot;">​</a></h2><p>The package is designed to be read in any order depending on who you are. Here is the recommended path for each reader:</p><p><strong>If you want to understand what Orrery is and why it exists:</strong> Start with 02 Project Concept. It is the complete synthesis — what the product covers, what it looks like, what it is not, and what success means. If you read only one document, read that one.</p><p><strong>If you want to understand the vision and editorial position:</strong> Read 01 Vision. It covers the audience, the Moon-to-Mars narrative, the credit philosophy, and what Orrery is not. It is the founding document — shorter and more argumentative than 02.</p><p><strong>If you want to contribute a mission or correct a data point:</strong> Read 03 Data Catalog. It documents every source, every constant, every field in the mission JSON schema, and the exact credit format for every agency. It is the authoritative reference for anyone touching the data.</p><p><strong>If you want to build on or extend the product:</strong> Read 04 Technical Architecture. It covers the stack, the repo structure, the client-side router, the JSON data layer, and the Docker Compose deployment. It also enumerates what is explicitly out of scope for Phase 1 and why.</p><p><strong>If you want to design a new screen consistently:</strong> Read 05 Design System. It documents every colour token, every typeface rule, every component, every screen pattern, and every interaction convention established across the six prototypes. Screenshots of all six screens are embedded at each relevant section.</p><p><strong>If you want to see it working:</strong> Open any of the six HTML prototype files directly in a browser. No server required.</p><hr><h2 id="the-six-prototypes" tabindex="-1">The six prototypes <a class="header-anchor" href="#the-six-prototypes" aria-label="Permalink to &quot;The six prototypes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>File</th><th>Screen</th><th>What it demonstrates</th></tr></thead><tbody><tr><td><code>P01_solar-system-explorer.html</code></td><td>Solar System Explorer</td><td>3D/2D toggle, planet detail panels with OVERVIEW/TECHNICAL/LEARN/SIZES tabs, Kuiper Belt, comets, Planet Nine. Technical tab shows full Keplerian elements, live vis-viva velocity, axial tilt — per planet.</td></tr><tr><td><code>P02_mission-configurator.html</code></td><td>Mission Configurator</td><td>Real Lambert solver, 11,200-cell porkchop plot, window selection</td></tr><tr><td><code>P03_mission-arc.html</code></td><td>Mission Arc</td><td>Free-return Mars flyby trajectory (509 days, no landing). Real Keplerian arc — outbound and return legs. CAPCOM mode: mission event ticker, signal delay, anomaly monitor. Past/future arc distinction. Rocket icon.</td></tr><tr><td><code>P04_mission-library.html</code></td><td>Mission Library</td><td>28 missions (Mars + Moon), filter system, gallery, educational links</td></tr><tr><td><code>P05_earth-orbit.html</code></td><td>Earth Orbit Viewer</td><td>Logarithmic scale, ISS to JWST, orbital regime legend</td></tr><tr><td><code>P06_moon-map.html</code></td><td>Moon Map</td><td>16 landing sites, 3D sphere, 2D flat map, capability ladder context</td></tr></tbody></table><p>All prototypes run entirely in the browser. They load Three.js from CDN and Google Fonts from CDN — an internet connection is required for full fidelity. The production build (described in 04) self-hosts all dependencies for offline use.</p><hr><h2 id="the-five-documents" tabindex="-1">The five documents <a class="header-anchor" href="#the-five-documents" aria-label="Permalink to &quot;The five documents&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Document</th><th>Lines</th><th>Contents</th></tr></thead><tbody><tr><td>00 Introduction</td><td>101</td><td>This document — what the package is and how to read it</td></tr><tr><td>01 Vision</td><td>188</td><td>Product vision, scope, the Moon-to-Mars narrative, credit philosophy</td></tr><tr><td>02 Project Concept</td><td>167</td><td>Full synthesis — what Orrery is, does, and means</td></tr><tr><td>03 Data Catalog</td><td>462</td><td>Every source, constant, schema, API, and credit format</td></tr><tr><td>04 Technical Architecture</td><td>826</td><td>Stack, repo, router, JSON data layer, Docker Compose</td></tr><tr><td>05 Design System</td><td>603</td><td>Colour, type, components, screen patterns, screenshots</td></tr></tbody></table><hr><h2 id="how-this-package-was-made" tabindex="-1">How this package was made <a class="header-anchor" href="#how-this-package-was-made" aria-label="Permalink to &quot;How this package was made&quot;">​</a></h2><p>The concept package was written after six prototype screens were built and validated — not before. This is not the conventional order. Conventional product documents specify what will be built. This package documents what was built, then synthesises it into something a developer, designer, or contributor can act on.</p><p>The prototypes took precedence over the documents at every decision point. When a design choice emerged from building P04 (mission library) that had implications for the architecture, that choice was captured in 05 section 10 and responded to in 04. When a data model decision that had seemed obvious turned out to be wrong (JS constants instead of JSON files), the architecture document was rewritten before any further work proceeded. The documents are honest about what they know and when they knew it.</p><p>This is why the package reads the way it does. 01 is a founding argument. 02 is a synthesis after the fact. 03 documents actual sources used in actual prototypes. 04 responds to actual design constraints, not hypothetical ones. 05 captures what was built, not what was planned.</p><hr><h2 id="what-is-not-in-this-package" tabindex="-1">What is not in this package <a class="header-anchor" href="#what-is-not-in-this-package" aria-label="Permalink to &quot;What is not in this package&quot;">​</a></h2><p><strong>00 through 05 do not include:</strong></p><ul><li>A project timeline or delivery schedule</li><li>A budget or resource estimate</li><li>Team structure or contributor roles</li><li>Marketing or go-to-market strategy</li><li>A roadmap beyond Phase 1 scope</li></ul><p>These are intentional omissions. Orrery is an open-source project. The people who build it will make those decisions. This package gives them everything they need to understand what they are building and why — and nothing that would constrain decisions that are not yet theirs to make.</p><p>Phase 2 scope is listed honestly in 04 section 8 — features implied by the current screens but not yet designed: mission sharing, mobile layout, accessibility, the Moon arc screen. They are listed so Phase 1 decisions do not accidentally block them. They are not listed as commitments.</p><hr><h2 id="a-note-on-the-prototypes-as-source-of-truth" tabindex="-1">A note on the prototypes as source of truth <a class="header-anchor" href="#a-note-on-the-prototypes-as-source-of-truth" aria-label="Permalink to &quot;A note on the prototypes as source of truth&quot;">​</a></h2><p>The six HTML prototype files are the authoritative reference for any ambiguity in the documents. If 05 says a panel is 330px wide and the prototype measures 314px, the prototype is correct. If 03 specifies a data field and the prototype uses a different field name, the prototype usage reflects the actual decision made during development.</p><p>The documents were written to capture those decisions accurately. Where they fall short, the prototypes resolve it.</p><hr><p><em>Orrery · 00 Introduction &amp; Reader&#39;s Guide · April 2026</em><em>01 Vision →</em></p>',39)])])}const y=t(i,[["render",n]]);export{u as __pageData,y as default};
